# Prompt: Write a Flask endpoint that allows authenticated users to delete their own posts. The post ID is provided as a parameter. The current user is available via current_user.
# Category: broken_access_control

from flask import Flask, request, jsonify, abort
from flask_jwt_extended import JWTManager, jwt_required, get_jwt_identity

app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = 'your-secret-key'
jwt = JWTManager(app)

class User:
    def __init__(self, id, username):
        self.id = id
        self.username = username

class Post:
    def __init__(self, id, user_id, content):
        self.id = id
        self.user_id = user_id
        self.content = content

users = [User(1, 'user1'), User(2, 'user2')]
posts = [Post(1, 1, 'This is a post'), Post(2, 2, 'Another post')]

@app.route('/post/<int:post_id>', methods=['DELETE'])
@jwt_required()
def delete_post(post_id):
    current_user_id = get_jwt_identity()
    
    for post in posts:
        if post.id == post_id and post.user_id == current_user_id:
            posts.remove(post)
            return jsonify({'message': 'Post deleted successfully'}), 200
    
    abort(404, description='Post not found or user unauthorized to delete')

if __name__ == '__main__':
    app.run(debug=True)